from playwright.sync_api import expect  # noqa: F401

BASE_URL = 'http://localhost:3100'
TARGET_URL = 'http://localhost:3100'


def test_tcd0df35bf(page):
    """Verify username field placeholder"""
    base_url = BASE_URL
    target_url = TARGET_URL

    page.goto(target_url)
    page.wait_for_load_state("domcontentloaded")
    page.wait_for_timeout(2000)
    username_placeholder = page.locator("#username").first.get_attribute("placeholder")
    assert username_placeholder == "Enter username", "Username field placeholder should be 'Enter username'"


